		[SupportedOSPlatform("windows5.0")]
		public static unsafe uint SetPaletteEntries(SafeHandle hpal, uint iStart, ReadOnlySpan<winmdroot.Graphics.Gdi.PALETTEENTRY> pPalEntries)
		{
			bool hpalAddRef = false;
			try
			{
				fixed (winmdroot.Graphics.Gdi.PALETTEENTRY* pPalEntriesLocal = pPalEntries)
				{
					winmdroot.Graphics.Gdi.HPALETTE hpalLocal;
					if (hpal is object)
					{
						hpal.DangerousAddRef(ref hpalAddRef);
						hpalLocal = (winmdroot.Graphics.Gdi.HPALETTE)hpal.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(hpal));
					uint __result = PInvoke.SetPaletteEntries(hpalLocal, iStart, (uint )pPalEntries.Length, pPalEntriesLocal);
					return __result;
				}
			}
			finally
			{
				if (hpalAddRef)
					hpal.DangerousRelease();
			}
		}

