		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.Foundation.BOOL EngAssociateSurface(winmdroot.Devices.Display.HSURF hsurf, winmdroot.Devices.Display.HDEV hdev, uint flHooks);

